import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote — base premiums and edge cases", () => {
    it("empty item list → premium 5 G (only processing fee)", () => {
      const result = runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [] }],
      });
      expect(result).toEqual({ results: [{ premium: 5 }] });
    });
    it("single plain sword for newcomer → 100 base + 10 first-insurance + 5 fee = 115 G", () => {
      const result = runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "sword" }] }],
      });
      expect(result).toEqual({ results: [{ premium: 115 }] });
    });
    it.todo("single amulet for newcomer → 60 + 6 first-ins + 5 fee = 71 G");
    it.todo("single staff for newcomer → 80 + 8 first-ins + 5 fee = 93 G");
    it.todo("single potion for newcomer → 40 + 4 first-ins + 5 fee = 49 G");
  });

  describe("Quote — component blocks", () => {
    it.todo("2 runes → 50 G base premium (+ fee)");
    it.todo("3 runes → 60 G base premium (block applies)");
    it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
    it.todo("7 runes → 175 G base premium (no block beyond exactly 3)");
    it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
    it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
  });

  describe("Quote — premium modifiers", () => {
    it.todo("cursed sword adds 50% of cursed item's base premium (cursed sword → 100 + 50 + fee)");
    it.todo("highly enchanted sword (enchantment 5) adds 30% surcharge to that item");
    it.todo("sword with enchantment 4 → no high-enchantment surcharge");
    it.todo("cursed sword with enchantment 5 → both surcharges apply");
    it.todo("long-standing customer (≥ 2 years) → 20% loyalty discount on policy base");
    it.todo("customer with exactly 2 years → loyalty discount applies");
    it.todo("first insurance carries 10% initial assessment surcharge on policy base");
    it.todo("follow-up contract (after first) receives 15% discount on policy base");
    it.todo("multi-item: cursed sword + plain amulet → base 160, +50 curse = 210 before fee");
  });

  describe("Quote — rounding", () => {
    it.todo("premium 197.5 G → final premium 198 G (rounded up in MHPCO's favor)");
  });

  describe("Quote — integration examples", () => {
    it.todo("newcomer (0 years) with cursed sword (steel, ench 3) → premium 165 G");
    it.todo("long-standing (3 years) 2nd quote, cursed sword (steel, ench 7) → premium 160 G");
  });

  describe("Quote — errors", () => {
    it.todo("unknown item type (e.g. broomstick) → throws / scenario rejected");
  });

  describe("Claim — standard reimbursement", () => {
    it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (− 100 deductible)");
    it.todo("damage to a rune (insurance 250 G), damage 200 G → payout 100 G (− 100 deductible)");
  });

  describe("Claim — special clauses", () => {
    it.todo("high-enchantment item (ench ≥ 8): 50% of damage, then deductible");
    it.todo("dragon-material item: full reimbursement, then deductible");
    it.todo("dragon sword, ench 9, damage 1000 → 400 (50% rule wins; 500 − 100)");
    it.todo("dragon sword, ench 5, damage 800 → 700 (dragon only; 800 − 100)");
    it.todo("steel sword, ench 9, damage 1000 → 400 (50% then deductible)");
    it.todo("dragon sword, ench 8, damage 1000 → 400 (high-ench applies, then deductible)");
  });

  describe("Claim — deductible per event/item", () => {
    it.todo("dragon attack on sword (500) and amulet (300) → payout 600 (deductible per item)");
  });

  describe("Claim — multiple items of same type", () => {
    it.todo("policy with two swords → insurance sum 2000, cap 4000");
    it.todo("damages array with two sword entries → each treated as separate damage with own deductible");
    it.todo("damages array has more entries of a type than the policy covers → claim rejected");
  });

  describe("Claim — cap exhaustion", () => {
    it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
    it.todo("cursed sword (premium with modifiers 165 G) → cap based on insurance value (2000)");
    it.todo("sword + 3 runes (block) → insurance sum 1750 G; block does not affect cap");
    it.todo("sword cap 2000; claim 1500 → payout 1400, remaining 600");
    it.todo("after first 1400 claim, second claim 1500 → payout 600, remaining 0");
  });

  describe("Claim — payout rounding", () => {
    it.todo("payout calculation 350.5 G → final payout 350 G (rounded down in MHPCO's favor)");
  });

  describe("Claim — errors", () => {
    it.todo("damage references item not in policy (e.g. amulet damage on sword-only policy) → rejected");
    it.todo("damage with negative amount → rejected");
  });
});

