const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const basePremiumForItems = (items: Item[]): number => {
  const countsByType = new Map<string, number>();
  let total = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
    } else {
      total += BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
    }
  }
  for (const count of countsByType.values()) {
    if (count === BLOCK_SIZE) {
      total += BLOCK_PREMIUM;
    } else {
      total += count * (BASE_PREMIUM_BY_TYPE.rune ?? 0);
    }
  }
  return total;
};

const quotePremium = (items: Item[]): number => {
  const policyBase = basePremiumForItems(items);
  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
  return Math.ceil(policyBase + firstInsuranceSurcharge + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map((step) => ({
    premium: quotePremium(step.items),
  }));
  return { results };
};

