const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

const CURSE_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const itemSurchargeRate = (item: Item): number => {
  let rate = 0;
  if (item.cursed) rate += CURSE_SURCHARGE_RATE;
  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
    rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
  }
  return rate;
};

const basePremiumForItems = (items: Item[]): number => {
  const componentsByType = new Map<string, Item[]>();
  let total = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      const list = componentsByType.get(item.type) ?? [];
      list.push(item);
      componentsByType.set(item.type, list);
    } else {
      const itemBase = BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
      total += itemBase * (1 + itemSurchargeRate(item));
    }
  }
  for (const components of componentsByType.values()) {
    if (components.length === BLOCK_SIZE) {
      total += BLOCK_PREMIUM;
    } else {
      total += components.length * (BASE_PREMIUM_BY_TYPE.rune ?? 0);
    }
  }
  return total;
};

const quotePremium = (items: Item[]): number => {
  const policyBase = basePremiumForItems(items);
  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
  return Math.ceil(policyBase + firstInsuranceSurcharge + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map((step) => ({
    premium: quotePremium(step.items),
  }));
  return { results };
};

